import UIKit
import CoreData
import Foundation

// Core Data Stack Setup
class AppDelagate: UIResponder, UIApplicationDelegate {
    let persistentContainer = NSPersistentContainer(name: "Stocks")

    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        persistentContainer.load()
        return true
    }
}

// Trading API Client
class TradingAPI: NSObject {
    let apiEndpoint = "https://api.example.com/stocks"
    var session: URLSession

    init(session: URLSession = .shared) {
        self.session = session
    }

    func getStocks(completion: @escaping ([Stock]?, Error?) -> Void) {
        guard let url = URL(string: "\(apiEndpoint)/stocks") else { return }
        var request = URLRequest(url: url, cachePolicy: .useProtocolCachePolicy)
        request.httpMethod = "GET"

        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }

            do {
                let stocksResponse = try JSONDecoder().decode([Stock].self, from: data!)
                completion(stocksResponse, nil)
            } catch {
                completion(nil, error)
            }
        }.resume()
    }
}

// Stock Model
struct Stock: Codable, Identifiable {
    let id = UUID()
    var symbol: String
    var name: String
    var price: Double

    static func ==(lhs: Stock, rhs: Stock) -> Bool {
        return lhs.id == rhs.id
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(id)
    }
}

// Portfolio Management
class PortfolioManager: NSObject {
    var stocks: [Stock] = []
    let persistentContainer: NSPersistentContainer

    init(persistentContainer: NSPersistentContainer = AppDelagate().persistentContainer) {
        self.persistentContainer = persistentContainer
    }

    func addStock(_ stock: Stock) {
        stocks.append(stock)
        saveToCoreData()
    }

    func removeStock(_ stock: Stock) {
        if let index = stocks.firstIndex(of: stock) {
            stocks.remove(at: index)
            saveToCoreData()
        }
    }

    private func saveToCoreData() {
        guard let appDelegate = UIApplication.shared.delegate as? AppDelagate else { return }
        let context = appDelegate.persistentContainer.viewContext

        do {
            try context.save()
        } catch {
            print("Error saving to Core Data: \(error)")
        }
    }
}

// Trade Execution
class TradeExecutor: NSObject {
    var portfolioManager: PortfolioManager
    var tradingAPI: TradingAPI

    init(portfolioManager: PortfolioManager = PortfolioManager(), tradingAPI: TradingAPI = TradingAPI()) {
        self.portfolioManager = portfolioManager
        self.tradingAPI = tradingAPI
    }

    func executeTrade(_ trade: Trade) {
        // Execute the trade using the trading API
        guard let token = trade.token else { return }
        tradingAPI.getStocks { [weak self] stocks, error in
            if let error = error {
                print("Error executing trade: \(error)")
                return
            }

            if let stock = stocks?.first(where: { $0.symbol == trade.symbol }) {
                self?.portfolioManager.addStock(stock)
            }
        }
    }
}

// Trade Model
struct Trade: Codable, Identifiable {
    let id = UUID()
    var symbol: String
    var quantity: Int
    var price: Double

    static func ==(lhs: Trade, rhs: Trade) -> Bool {
        return lhs.id == rhs.id
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(id)
    }
}